SELECT t0.*, t2.form_name FROM form_submit t0
LEFT JOIN user t1 ON t1.user_id = t0.user_id AND t1.deleted = 0
LEFT JOIN form t2 ON t2.form_id = t0.form_id AND t2.deleted = 0
WHERE t0.deleted = 0
 AND t0.form_id = #{formId} 
 AND t0.user_id = #{userId} 
 AND t0.status = #{status} 
 AND t1.user_name = #{userName} 
 AND t1.show_name LIKE CONCAT('%', #{showName}, '%') 
ORDER BY t0.submit_id DESC
LIMIT #{page}, #{limit}

SELECT COUNT(1) FROM form_submit t0
LEFT JOIN user t1 ON t1.user_id = t0.user_id AND t1.deleted = 0
LEFT JOIN form t2 ON t2.form_id = t0.form_id AND t2.deleted = 0
WHERE t0.deleted = 0
 AND t0.form_id = #{formId} 
 AND t0.user_id = #{userId} 
 AND t0.status = #{status} 
 AND t1.user_name = #{userName} 
 AND t1.show_name LIKE CONCAT('%', #{showName}, '%')
